sql:
SELECT DISTINCT start_station_name
FROM trips
WHERE tripduration > 600;

SELECT t.bike_id, t.tripduration
FROM trips t
INNER JOIN bikes b ON t.bike_id = b.bike_id;

SELECT DISTINCT u.user_id
FROM users u
WHERE u.user_id NOT IN (
  SELECT t.user_id
  FROM trips t
) AND u.user_id IN (
  SELECT s.user_id
  FROM subscriptions s
  WHERE s.end_date > date('now')
);

external_knowledge:
- "chariots" refers to the bikes in the context of the query; 
- "male and female travelers" refers to users grouped by gender; 
- "weight of journeys long and short" metaphorically describes the average trip duration; 
- "total earnings from these steeds surpassed the golden threshold of $5000" suggests the bikes must have generated more than $5000 in total revenue.

sql:
SELECT total_revenue
FROM bike_stats
WHERE bike_id = 1;

SELECT bike_id, maintenance_required
FROM bikes
WHERE maintenance_required = 1;

SELECT B.bike_model, BS.total_trips 
FROM bikes B
INNER JOIN bike_stats BS ON B.bike_id = BS.bike_id;

external_knowledge:
fairer sex refers to female individuals;
short walk to a brief day refers to a trip duration between 60 seconds and 3600 seconds;
common expense refers to the average cost of all trips;
ticket price refers to the cost of the trip;
Elm Street refers to stations with names containing "Elm St";
still active bikes mean bikes with a status of 'available'.

- A user type can be either 'Subscriber' or 'Casual'.;
- The 'most popular bike' refers to the bike model with the highest number of trips.;
- The 'most frequented stations' are those stations that have the highest number of starts or ends, indicating popularity.;
- 'Active subscriptions' are ongoing subscriptions for a user type.;

sql:
SELECT DISTINCT bikes.bike_model
FROM bikes
JOIN trips ON bikes.bike_id = trips.bike_id;

SELECT users.user_id, subscriptions.subscription_id
FROM users
JOIN subscriptions ON users.user_id = subscriptions.user_id;

SELECT age
FROM trips
WHERE tripduration = (SELECT MAX(tripduration) FROM trips);

SELECT user_id, COUNT(*) as subscription_count
FROM subscriptions
GROUP BY user_id;

SELECT AVG(ud.age) AS average_age
FROM trips t
JOIN user_demographics ud ON t.user_id = ud.user_id;

SELECT COUNT(*)
FROM trip_summary
WHERE trip_purpose = 'leisure';

SELECT gender 
FROM users 
WHERE user_id = (SELECT user_id FROM access_logs WHERE action = 'trip_start');
